def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about astronauts (or related entities) into a
    fluent English sentence.  The function groups triples by their subject and
    builds a clause for each predicate, then joins the clauses into a single
    (or a few) readable sentences.
    """
    if not triples:
        return ""

    # Helper to turn a predicate/object pair into a phrase
    def phrase(subj: str, pred: str, obj: str) -> str:
        """Return a natural‑language phrase for a single predicate."""
        # Strip surrounding quotes and whitespace
        obj = obj.strip().strip('"')
        # Normalise predicate for lookup
        p = pred.lower().replace(" ", "")
        # Helper to format ISO dates nicely
        def fmt_date(d: str) -> str:
            try:
                from datetime import datetime
                dt = datetime.strptime(d, "%Y-%m-%d")
                return dt.strftime("%B %-d, %Y")
            except Exception:
                return d

        # Mapping of predicates to phrase templates
        if p == "birthdate":
            return f"{subj} was born on {fmt_date(obj)}"
        if p == "birthplace":
            return f"{subj} was born in {obj}"
        if p == "deathdate":
            return f"{subj} died on {fmt_date(obj)}"
        if p == "deathplace":
            return f"{subj} died in {obj}"
        if p == "nationality":
            low_obj = obj.lower()
            if "united states" in low_obj:
                return f"{subj} is a United States national"
            return f"{subj} has nationality {obj}"
        if p == "dateofretirement":
            # Expecting formats like "June 1981" or ISO date
            try:
                from datetime import datetime
                # Try ISO first
                dt = datetime.strptime(obj, "%Y-%m-%d")
                fmt = dt.strftime("%B %-d, %Y")
            except Exception:
                # Try "Month Year" already
                fmt = obj
            return f"{subj} retired in {fmt}"
        if p == "senators":
            # subject is a region, object is a person
            return f"{obj} is a senator from {subj}"
        if p == "occupation":
            return f"{subj} was a {obj}"
        if p == "status":
            low = obj.lower()
            if low == "retired":
                return f"{subj} is retired"
            return f"{subj} is {low}"
        if p == "selectedbynasa":
            return f"{subj} was selected by NASA in {obj}"
        if p == "mission":
            return f"{subj} was a crew member of {obj}"
        if p == "timeinspace":
            try:
                mins = float(obj)
                hrs = int(mins // 60)
                rem = int(mins % 60)
                if hrs:
                    return f"{subj} spent {hrs} hour{'s' if hrs>1 else ''}" + (f" and {rem} minute{'s' if rem!=1 else ''}" if rem else "") + " in space"
                else:
                    return f"{subj} spent {rem} minute{'s' if rem!=1 else ''} in space"
            except Exception:
                return f"{subj} spent {obj} minutes in space"
        if p == "title":
            return f"{subj} held the title of {obj}"
        if p == "award":
            return f"{subj} received the {obj}"
        if p == "awards":
            return f"{subj} received {obj} awards"
        if p == "ribbonaward":
            return f"{subj} was awarded the {obj}"
        if p == "operator":
            return f"The {subj} was operated by {obj}"
        if p == "commander":
            return f"{obj} was the commander of {subj}"
        if p == "backuppilot":
            return f"{subj}'s backup pilot was {obj}"
        if p == "crewmembers":
            return f"{obj} was a crew member of {subj}"
        if p == "alternativename":
            return f"{subj} is also known as {obj}"
        if p == "servedaschiefoftheastronautofficein":
            return f"{subj} served as Chief of the Astronaut Office in {obj}"
        if p == "representative":
            return f"{obj} was the representative of {subj}"
        if p == "bird":
            return f"The {obj} is the state bird of {subj}"
        # Additional domain‑specific predicates
        if p == "part":
            return f"{subj} is part of {obj}"
        if p == "ispartof":
            return f"{subj} is part of {obj}"
        if p == "partsType".lower():
            return f"{subj}'s parts type is {obj}"
        if p == "fossil":
            return f"{obj} is a fossil from {subj}"
        if p == "gemstone":
            return f"{subj}'s gemstone is {obj}"
        if p == "mascot":
            return f"The mascot of {subj} is {obj}"
        if p == "leader":
            return f"{obj} is the leader of {subj}"
        if p == "affiliation":
            return f"{subj} is affiliated with {obj}"
        if p == "competein":
            return f"{subj} competes in {obj}"
        if p == "president":
            return f"{obj} is the president of {subj}"
        if p == "higher":
            return f"{subj} is lower than {obj}"
        if p == "cosparid":
            return f"{subj} has COSPAR ID {obj}"
        if p == "utcoffset":
            return f"{subj} has a UTC offset of {obj}"
        # Generic fallback
        return f"{subj} {pred} {obj}"

    # First, collect mission‑centric information so we can combine crew members, commander and backup pilot.
    from collections import defaultdict

    # astronauts linked to a mission via the "mission" predicate
    mission_to_astronauts = defaultdict(list)
    # crew members linked via the "crewMembers" predicate (subject is the mission)
    mission_to_crew = defaultdict(list)
    # commander and backupPilot (subject is the mission)
    mission_to_commander = {}
    mission_to_backup = {}

    # keep other triples that are not mission‑related
    other_triples = []

    for t in triples:
        pred = t.predicate.lower().replace(" ", "")
        if pred == "mission":
            mission_to_astronauts[t.object].append(t.subject)
        elif pred == "crewmembers":
            mission_to_crew[t.subject].append(t.object)
        elif pred == "commander":
            mission_to_commander[t.subject] = t.object
        elif pred == "backuppilot":
            mission_to_backup[t.subject] = t.object
        else:
            other_triples.append(t)

    def join_names(names):
        """Human‑readable joining of a list of names."""
        if not names:
            return ""
        if len(names) == 1:
            return names[0]
        return ", ".join(names[:-1]) + " and " + names[-1]

    sentences = []

    # Build sentences for each mission
    all_missions = set(mission_to_astronauts) | set(mission_to_crew)
    for mission in all_missions:
        crew = set(mission_to_astronauts.get(mission, [])) | set(mission_to_crew.get(mission, []))
        if crew:
            crew_phrase = f"{join_names(sorted(crew))} were crew members of {mission}"
            sentences.append(crew_phrase)
        if mission in mission_to_commander:
            sentences.append(f"{mission_to_commander[mission]} was the commander of {mission}")
        if mission in mission_to_backup:
            sentences.append(f"The backup pilot of {mission} was {mission_to_backup[mission]}")

    # Process the remaining triples (grouped by their subject)
    groups = defaultdict(list)
    for t in other_triples:
        groups[t.subject].append(t)

    for subj, items in groups.items():
        parts = [phrase(subj, t.predicate, t.object) for t in items]
        if len(parts) == 1:
            sent = parts[0]
        else:
            sent = ", ".join(parts[:-1]) + ", and " + parts[-1]
        sentences.append(sent)

    # Combine all sentences into a single fluent paragraph.
    if not sentences:
        return ""
    return " ".join(sentences) + "."

# EVOLVE-BLOCK-END

